import math

class Calculator:
    def add(self, a, b):
        return a + b

    def subtract(self, a, b):
        return a - b

    def multiply(self, a, b):
        return a * b

    def divide(self, a, b):
        if b == 0:
            raise ZeroDivisionError("Cannot divide by zero")
        return a / b

    def logarithm(self, x, base):
        if x <= 0:
            raise ValueError("Input must be a positive number")
        if base <= 0 or base == 1:
            raise ValueError("Base must be a positive number not equal to 1")
        return math.log(x) / math.log(base)

    def factorial(self, n):
        if n < 0:
            raise ValueError("Input must be a non-negative integer")
        if not isinstance(n, int):
            raise TypeError("Input must be an integer")
        return math.factorial(n)

    def sine(self, x):
        return math.sin(x)

    def cosine(self, x):
        return math.cos(x)

    def tangent(self, x):
        return math.tan(x)

    def square_root(self, x):
        if x < 0:
            raise ValueError("Input must be a non-negative number")
        return math.sqrt(x)

    def exponent(self, x, y):
        return x ** y

    def power(self, x, y):
        return x ** y

    def cube_root(self, x):
        return round(x ** (1/3), 3)

    def nth_root(self, x, n):
        if n == 0:
            raise ZeroDivisionError("Cannot divide by zero")
        if x < 0 and n % 2 == 0:
            raise ValueError("Input must be a non-negative number for even roots")
        return round(x ** (1/n), 3)

def main():
    calculator = Calculator()
    print(calculator.add(5, 3))
    print(calculator.subtract(5, 3))
    print(calculator.multiply(5, 3))
    print(calculator.divide(5, 3))
    print(calculator.logarithm(100, 10))
    print(calculator.factorial(5))
    print(calculator.sine(math.pi/2))
    print(calculator.cosine(0))
    print(calculator.tangent(math.pi/4))
    print(calculator.square_root(16))
    print(calculator.exponent(2, 3))
    print(calculator.power(2, 3))
    print(calculator.cube_root(27))
    print(calculator.nth_root(16, 2))

if __name__ == "__main__":
    main()

