import math

class Calculator:
    def add(self, a, b):
        return a + b

    def subtract(self, a, b):
        return a - b

    def multiply(self, a, b):
        return a * b

    def divide(self, a, b):
        if b == 0:
            raise ZeroDivisionError("Cannot divide by zero")
        return a / b

    def logarithm(self, base, number):
        if base <= 0 or number <= 0:
            raise ValueError("Base and number must be positive")
        return math.log(number) / math.log(base)

    def factorial(self, n):
        if n < 0:
            raise ValueError("Factorial is not defined for negative numbers")
        elif n == 0 or n == 1:
            return 1
        else:
            return n * self.factorial(n - 1)

    def power(self, base, exponent):
        return base ** exponent

    def square_root(self, number):
        if number < 0:
            raise ValueError("Square root of negative number is not a real number")
        return math.sqrt(number)

    def cube_root(self, number):
        return number ** (1/3)

    def sine(self, angle):
        return math.sin(math.radians(angle))

    def cosine(self, angle):
        return math.cos(math.radians(angle))

    def tangent(self, angle):
        return math.tan(math.radians(angle))

    def asin(self, number):
        if number < -1 or number > 1:
            raise ValueError("Input must be between -1 and 1")
        return math.degrees(math.asin(number))

    def acos(self, number):
        if number < -1 or number > 1:
            raise ValueError("Input must be between -1 and 1")
        return math.degrees(math.acos(number))

    def atan(self, number):
        return math.degrees(math.atan(number))

