        result = x / y
        self.history.append(f"Divided {x} by {y}, result = {result}")
        return result

    def factorial(self, n):
        if not isinstance(n, int):
            raise TypeError("Input must be an integer")
        if n < 0:
            raise ValueError("Input must be a non-negative integer")
        result = 1
        for i in range(1, n + 1):
            result *= i
        self.history.append(f"Calculated factorial of {n}, result = {result}")
        return result

    def root(self, x, n):
        if x < 0 and n % 2 == 0:
            raise ValueError("Cannot calculate even root of negative number")
        result = x ** (1 / n)
        self.history.append(f"Calculated {n}th root of {x}, result = {result}")
        return result

    def log(self, x, base):
        if x <= 0:
            raise ValueError("Input must be a positive number")
        if base <= 0 or base == 1:
            raise ValueError("Base must be a positive number not equal to 1")
        result = math.log(x) / math.log(base)
        self.history.append(f"Calculated logarithm of {x} with base {base}, result = {result}")
        return result

    def sin(self, x):
        result = math.sin(x)
        self.history.append(f"Calculated sine of {x}, result = {result}")
