    input_string = input_string.encode('utf-8')
    return base64.b64decode(input_string).decode('utf-8')

def generate_hmac(input_string, key):
    input_string = input_string.encode('utf-8')
    key = key.encode('utf-8')
    return hmac.new(key, input_string, hashlib.sha256).hexdigest()

